#!/bin/bash
source ~/.bashrc
job_slot_to_gpu=(-1 0 1 2 3 4)

env_parallel --delay 0 --eta -j $((${#job_slot_to_gpu[@]} - 1)) --colsep , --header : CUDA_VISIBLE_DEVICES='${job_slot_to_gpu[(( ({%} % (${#job_slot_to_gpu[@]} - 1) ) + 1 ))]}' 'python src/dafm/main.py +experiment=Lorenz63Spantini2022 filter=EnsembleKalmanFilterPerturbedObservations filter.gaspari_cohn_localization_radius=null setting.observe_every_n_time_steps={observe_every_n_time_steps} setting.reference_filter={reference_filter} "setting.observes=[{_target_:conf.observe.ObserveATan,order:0}]" setting.obs_noise_std=.1' ::: $(duckdb runs.sqlite -c "copy (with observe_ids as (select id from ObserveATan), da_setting_candidates as (select DataAssimilationSetting from DataAssimilationSetting__Observe group by DataAssimilationSetting having sum(Observe in (select id from observe_ids)) = (select count(*) from observe_ids)) select alt_id as reference_filter, observe_every_n_time_steps from Conf join da_setting_candidates using (DataAssimilationSetting) join DataAssimilationSetting on Conf.DataAssimilationSetting = DataAssimilationSetting.id join DynamicalSystemImpl on DataAssimilationSetting.DynamicalSystemImpl = DynamicalSystemImpl.id join Lorenz63 on DynamicalSystemImpl.DynamicalSystem = Lorenz63.id join BootstrapParticleFilter on Conf.Filter = BootstrapParticleFilter.id where DynamicalSystemImpl.rng_seed = 2376999025 and observe_every_n_time_steps in (2, 4, 8, 16) and save_ensemble_stats and obs_noise_std = .1) to '/dev/stdout';")
# env_parallel --delay 0 --eta -j $((${#job_slot_to_gpu[@]} - 1)) --colsep , --header : CUDA_VISIBLE_DEVICES='${job_slot_to_gpu[{%}]}' python src/dafm/main.py +experiment=Lorenz63Spantini2022 filter=EnsembleKalmanFilterPerturbedObservations filter.gaspari_cohn_localization_radius=null filter.inflation_scale={inflation_scale} ensemble_size={ensemble_size} observe_every_n_time_steps=2 ::: $(duckdb runs.sqlite -c "copy (select * from sweep_lorenz63spantini2022_inflation_scale cross join sweep_lorenz63spantini2022_ensemble_size) to '/dev/stdout'")
